{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "if echo $(jq -r '.tool_input.command') | grep -q 'git commit'; then npm run lint; fi"
          }
        ]
      }
    ]
  }
}

{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Edit",
        "hooks": [
          {
            "type": "command",
            "command": "FILE=$(jq -r '.tool_input.file_path'); if echo $FILE | grep -qE '(\\.env|config/production)'; then echo '{\"decision\": \"block\", \"reason\": \"Arquivo protegido\"}'; fi"
          }
        ]
      }
    ]
  }
}

{
  "hooks": {
    "Stop": [
      {
        "matcher": "*",
        "hooks": [
          {
            "type": "prompt",
            "prompt": "Antes de parar, verifique: todos os testes passam? Há arquivos sem salvar? O código compila? Retorne 'approve' ou 'block' com motivo."
          }
        ]
      }
    ]
  }
}
